from typing import Any

def extract_path(data: Any, path: str) -> Any:
    current = data
    for part in path.split("."):
        if part.endswith("]"):
            key, idx_part = part[:-1].split("[")
            if key:
                current = current[key]
            index = int(idx_part)
            current = current[index]
        else:
            current = current[part]
    return current
```

